import React, { useState } from 'react';

function RegistroEntrevistador({ onVolver }) {
  const [nombre, setNombre] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [mensaje, setMensaje] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setMensaje('');

    if (!nombre || !email || !password) {
      setError('Todos los campos son obligatorios.');
      return;
    }

    try {
      const response = await fetch('http://localhost/sistema-entrevistas/backend/api/crear_entrevistador.php', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nombre, email, password })
      });

      const data = await response.json();
      if (data.status === 'ok') {
        setMensaje('✅ Registrado correctamente. Ahora puedes iniciar sesión.');
        setNombre('');
        setEmail('');
        setPassword('');
      } else {
        setError(data.mensaje || 'Ocurrió un error.');
      }
    } catch (err) {
      console.error(err);
      setError('No se pudo conectar con el servidor.');
    }
  };

  return (
    <form onSubmit={handleSubmit} style={{ maxWidth: '400px', margin: '0 auto' }}>
      <h2>Crear cuenta de entrevistador</h2>

      <label>Nombre completo:</label>
      <input
        type="text"
        value={nombre}
        onChange={(e) => setNombre(e.target.value)}
        required
        style={{ width: '100%', padding: '8px', marginBottom: '10px' }}
      />

      <label>Email:</label>
      <input
        type="email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        required
        style={{ width: '100%', padding: '8px', marginBottom: '10px' }}
      />

      <label>Contraseña:</label>
      <input
        type="password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        required
        style={{ width: '100%', padding: '8px', marginBottom: '10px' }}
      />

      {error && <p style={{ color: 'red' }}>{error}</p>}
      {mensaje && <p style={{ color: 'green' }}>{mensaje}</p>}

      <button type="submit" style={{
        width: '100%',
        padding: '10px',
        backgroundColor: '#28a745',
        color: 'white',
        border: 'none',
        borderRadius: '6px',
        marginBottom: '10px'
      }}>
        Registrarse
      </button>

      <button
        type="button"
        onClick={onVolver}
        style={{
          width: '100%',
          padding: '10px',
          backgroundColor: '#6c757d',
          color: 'white',
          border: 'none',
          borderRadius: '6px'
        }}
      >
        Volver al login
      </button>
    </form>
  );
}

export default RegistroEntrevistador;
